const streakDefaults = { bedtime:5, bedtimeConsistency:5, sleepDuration:6, wakeTime:5, sleepGoalNights:5, meditation:5, breathing:5, mostSteps:5, dailyStepTarget:5, steps:5, screenFreeBeforeBed:5, socialMediaFree:5, strength:3, running:3, cycling:3 };
