const $ = s => document.querySelector(s); const $$ = s => Array.from(document.querySelectorAll(s));
const todayKey = () => (window.__oneUpNow ? window.__oneUpNow() : new Date()).toISOString().slice(0,10);
const day = (offset=0, base=todayKey()) => { const d=new Date(`${base}T12:00:00Z`); d.setUTCDate(d.getUTCDate()+offset); return d.toISOString().slice(0,10); };
const num = v => Math.max(0, Number(v)||0); const clamp=(v,min=0,max=100)=>Math.max(min,Math.min(max,v)); const fmt = v => Math.round(v).toLocaleString('da-DK');
const read = (k,f) => { try { return JSON.parse(localStorage.getItem(k)) ?? f; } catch { return f; } }; const save=(k,v)=>localStorage.setItem(k,JSON.stringify(v));
