function defaultActivitySettings(){return Object.fromEntries(Object.entries(activities).map(([id,a])=>[id,{enabled:a.enabled,goal:a.goal,front:true,streakEnabled:['bedtime','meditation','breathing','dailyStepTarget','screenFreeBeforeBed','socialMediaFree'].includes(id),dailyRequirement:a.goal,weeklyGoal:streakDefaults[id]||5,autoProtection:true,protectionEnabled:true,sleepCriteria:{duration:true,interval:false,bedtime:false,wake:false,screenfree:false},sleepMinHours:a.goal,sleepMinTolerance:0,sleepMinInterval:7,sleepMaxInterval:9,bedtimeTarget:'22:30',bedtimeTolerance:30,wakeTarget:'06:30',wakeTolerance:30}]))}
function normalizeSettings(){ const def=defaultActivitySettings(); Object.entries(ACTIVITY_ID_ALIASES).forEach(([oldId,newId])=>{ if(state.activitySettings[oldId]){ state.activitySettings[newId]={...(state.activitySettings[newId]||{}),...state.activitySettings[oldId]}; delete state.activitySettings[oldId]; }}); Object.keys(activities).forEach(id=>{ state.activitySettings[id]={...def[id],...(state.activitySettings[id]||{})}; if(state.activitySettings[id].dailyRequirement==null) state.activitySettings[id].dailyRequirement=state.activitySettings[id].goal; if(state.activitySettings[id].weeklyGoal==null) state.activitySettings[id].weeklyGoal=streakDefaults[id]||5; }); Object.keys(deprecatedActivities).forEach(id=>{ state.activitySettings[id]={enabled:false,goal:1,front:false,streakEnabled:false,dailyRequirement:1,weeklyGoal:5,deprecated:true,protectionEnabled:true,autoProtection:true,sleepCriteria:{duration:true},sleepMinHours:7,sleepMinTolerance:0,sleepMinInterval:7,sleepMaxInterval:9,bedtimeTarget:'22:30',bedtimeTolerance:30,wakeTarget:'06:30',wakeTolerance:30,...(state.activitySettings[id]||{})}; });  }
function migrateData(){
  if (Number(localStorage.getItem(KEYS.competitionVersion)||0) < COMPETITION_DATA_VERSION) { if(!localStorage.getItem(KEYS.competitions)) save(KEYS.competitions, []); localStorage.setItem(KEYS.competitionVersion, String(COMPETITION_DATA_VERSION)); }
  if (Number(localStorage.getItem(KEYS.version)||0) >= DATA_VERSION) return;
  const archived={}; oldVillageKeys.forEach(k=>{ const v=localStorage.getItem(k); if(v!==null){ archived[k]=v; localStorage.removeItem(k); }});
  if(Object.keys(archived).length) save(KEYS.archivedVillage, archived);
  const oldLog = read('oneupActivityLogV1', []); if(oldLog.length && !localStorage.getItem(KEYS.activityLog)) save(KEYS.activityLog, oldLog);
  const oldSettings = read('oneupActivitySettingsV1', null); if(oldSettings && !localStorage.getItem(KEYS.activitySettings)){ const next=defaultActivitySettings(); Object.entries(oldSettings).forEach(([id,v])=>{ if(next[id]) next[id]={...next[id],...v,goal:num(v.goal?.amount ?? v.goal ?? next[id].goal)}; }); save(KEYS.activitySettings,next); }
  localStorage.setItem(KEYS.version, String(DATA_VERSION));
}
function loadState(){ migrateData(); state={ points:num(localStorage.getItem(KEYS.points)), history:read(KEYS.history,{}), profile:read(KEYS.profile,{}), settings:{vibration:false,sounds:false,voice:false,weekStarts:'monday',units:'metric',language:'da',...(read(KEYS.settings,{})||{})}, activitySettings:read(KEYS.activitySettings, defaultActivitySettings()), log:read(KEYS.activityLog,[]), streakData:read(KEYS.streak,{version:STREAK_DATA_VERSION,manualProtection:{}}), competitions:read(KEYS.competitions,[]), competitionUi:read(KEYS.competitionUi,{collapsed:{}}) }; state.log.forEach(e=>e.activity=normalizeActivityId(e.activity)); state.competitions.forEach(c=>c.activities=sanitizeActivityIds(c.activities)); normalizeSettings(); ensureToday(); }
function persist(){ localStorage.setItem(KEYS.points,String(Math.round(state.points))); save(KEYS.history,state.history); save(KEYS.profile,state.profile); save(KEYS.settings,state.settings); save(KEYS.activitySettings,state.activitySettings); save(KEYS.activityLog,state.log); save(KEYS.streak,{version:STREAK_DATA_VERSION,manualProtection:state.streakData.manualProtection||{},summary:buildStreakSummary()}); save(KEYS.competitions,state.competitions); save(KEYS.competitionUi,state.competitionUi); }
function ensureToday(){ const t=todayKey(); state.history[t] ||= {date:t,entries:[],activityPoints:{},totalPoints:0,oneUpScore:0,steps:0,boxBreathingCount:0,breathing478Count:0}; }
function effectiveDate(e){ if(e.activity!=='sleep'&&e.activity!=='sleepDuration') return e.date; if(e.sleepDate) return e.sleepDate; if(e.end && e.start && e.end < e.start) return e.date; return e.date; }
function entries(date=todayKey(), id=null){ return state.log.filter(e=>effectiveDate(e)===date && (!id || e.activity===id)); }
function valueFor(id,date=todayKey()){ id=normalizeActivityId(id); const es=entries(date,id); if(id==='mostSteps'||id==='dailyStepTarget') return es.at(-1)?.value || entries(date,'steps').at(-1)?.value || state.history[date]?.steps || 0; if(id==='sleepDuration') return es.reduce((s,e)=>s+num(e.hours ?? e.value),0); return es.reduce((s,e)=>s+num(e.value),0); }
function goalFor(id){ if(id==='steps') id='dailyStepTarget'; else id=normalizeActivityId(id); return num(state.activitySettings[id]?.goal ?? activityMeta(id)?.goal); }
function dailyRequirementFor(id){ if(id==='steps') id='dailyStepTarget'; else id=normalizeActivityId(id); return num(state.activitySettings[id]?.dailyRequirement ?? goalFor(id)); }
function periodValue(id,date=todayKey()){ id=normalizeActivityId(id); if((activityMeta(id).period||'day')==='day') return valueFor(id,date); return [0,-1,-2,-3,-4,-5,-6].reduce((s,o)=>s+valueFor(id,day(o,date)),0); }
function activityPercent(id,date=todayKey()){ id=normalizeActivityId(id); const g=goalFor(id); if(id==='mostSteps') return Math.min(100, valueFor(id,date)/Math.max(1,goalFor('dailyStepTarget')||8000)*100); if(!g) return 0; if(id==='socialMediaFree') return scoreLessIsBetter(periodValue(id,date),g,null); return Math.min(100, periodValue(id,date)/g*100); }
function pointsForEntry(e){ const g=goalFor(e.activity); if(e.activity==='steps'||e.activity==='mostSteps'||e.activity==='dailyStepTarget') return Math.floor(num(e.value)/100); if(e.activity==='breathing') return num(e.value)*5; if(e.activity==='meditation') return Math.min(30,num(e.value)); if(e.activity==='strength') return 20; if(e.activity==='running') return Math.min(60,num(e.value))*2; if(e.activity==='cycling') return Math.min(60,num(e.value)); if(e.activity==='sleep'||e.activity==='sleepDuration') return num(e.hours ?? e.value)>=g?20:0; if(e.activity==='screenFreeBeforeBed') return num(e.value)>=g?15:0; if(e.activity==='socialMediaFree') return (e.mode==='usage'?num(e.value)<=g:num(e.value)>=g)?15:0; return 0; }
function minutes(t){ const [h,m]=(t||'00:00').split(':').map(Number); return h*60+m; }
function withinTime(value,target,tol){ const diff=Math.abs(((minutes(value)-minutes(target)+720+1440)%1440)-720); return diff<=num(tol); }
function sleepMet(date,id='sleepDuration'){ const s=state.activitySettings[id]||state.activitySettings.sleepDuration, es=entries(date,id), hours=id==='sleep'?es.reduce((sum,e)=>sum+num(e.hours ?? e.value),0):valueFor(id,date); if(!es.length) return false; const checks=[]; if(s.sleepCriteria?.duration) checks.push(hours+num(s.sleepMinTolerance||0)>=num(s.sleepMinHours||dailyRequirementFor('sleep'))); if(s.sleepCriteria?.interval) checks.push(hours>=num(s.sleepMinInterval||7)&&hours<=num(s.sleepMaxInterval||9)); if(s.sleepCriteria?.bedtime) checks.push(es.some(e=>withinTime(e.start,s.bedtimeTarget,s.bedtimeTolerance))); if(s.sleepCriteria?.wake) checks.push(es.some(e=>withinTime(e.end,s.wakeTarget,s.wakeTolerance))); if(s.sleepCriteria?.screenfree) checks.push(requirementMet('screenFreeBeforeBed',date)); return checks.length?checks.every(Boolean):hours>=dailyRequirementFor('sleep'); }
function requirementMet(id,date=todayKey()){ const legacySleep=id==='sleep'; if(!legacySleep) id=normalizeActivityId(id); if(!state.activitySettings[id]?.streakEnabled) return false; if(id==='sleepDuration'||legacySleep) return sleepMet(date, legacySleep?'sleep':'sleepDuration'); if(id==='socialMediaFree') { const es=entries(date,id); if(es.at(-1)?.mode==='usage') return num(es.at(-1).value)<=dailyRequirementFor(id); } return valueFor(id,date)>=dailyRequirementFor(id); }
function protectionUsed(id,date){ return !!state.streakData.manualProtection?.[id]?.[date]; }
function canProtect(id,date){ const s=state.activitySettings[id]; if(!s?.protectionEnabled) return false; if(requirementMet(id,date)) return false; if(protectionUsed(id,day(-1,date))||protectionUsed(id,day(1,date))) return false; const used14=[...Array(27)].some((_,i)=>protectionUsed(id,day(i-13,date))); return !used14; }
function maybeAutoProtect(id,date){ const s=state.activitySettings[id]; if(s?.autoProtection && canProtect(id,date)){ state.streakData.manualProtection[id] ||= {}; state.streakData.manualProtection[id][date]=true; return true; } return false; }
function dayComplete(id,date=todayKey(), useAuto=false){ if(requirementMet(id,date)) return true; if(protectionUsed(id,date)) return true; if(useAuto && maybeAutoProtect(id,date)) return true; return false; }
function allDates(){ const dates=new Set(Object.keys(state.history)); state.log.forEach(e=>dates.add(effectiveDate(e))); dates.add(todayKey()); return [...dates].sort(); }
function streakInfo(id,date=todayKey()){ let current=0; for(let i=0;i<730;i++){ if(dayComplete(id,day(-i,date), true)) current++; else break; } let best=0,cur=0,last=null; allDates().forEach(d=>{ if(dayComplete(id,d)){ cur++; last=d; } else cur=0; best=Math.max(best,cur); }); return {id,current,best,lastActiveDate:last,metToday:requirementMet(id,date),protectedToday:protectionUsed(id,date),completeToday:dayComplete(id,date),weekly:weeklyConsistency(id,date)}; }
function enabledStreakIds(){ return Object.keys(activities).filter(id=>state.activitySettings[id]?.enabled && state.activitySettings[id]?.streakEnabled); }
function weekStart(date=todayKey()){ const d=new Date(`${date}T12:00:00Z`), dow=d.getUTCDay(), off=state.settings.weekStarts==='sunday'?dow:(dow+6)%7; d.setUTCDate(d.getUTCDate()-off); return d.toISOString().slice(0,10); }
function weekDates(date=todayKey()){ const s=weekStart(date); return [0,1,2,3,4,5,6].map(i=>day(i,s)); }
function weeklyConsistency(id,date=todayKey()){ const dates=weekDates(date), done=dates.filter(d=>dayComplete(id,d)).length, goal=clamp(num(state.activitySettings[id]?.weeklyGoal||5),1,7), elapsed=dates.findIndex(d=>d===date)+1 || 7; return {done,goal,percent:Math.round(done/goal*100),onTrack:done>=Math.ceil(goal*elapsed/7),dates}; }
function activityWeights(ids){ const activeFocus=ids.filter(id=>focusActivities.includes(id)), other=ids.filter(id=>!focusActivities.includes(id)), w={}; if(activeFocus.length&&other.length){ activeFocus.forEach(id=>w[id]=0.60/activeFocus.length); other.forEach(id=>w[id]=0.40/other.length); } else ids.forEach(id=>w[id]=1/ids.length); return w; }
function consistencyScore(date=todayKey()){ const ids=enabledStreakIds(); if(!ids.length) return 0; const weights=activityWeights(ids); let daily=0,weekly=0,stability=0; ids.forEach(id=>{ daily+=(dayComplete(id,date)?100:0)*weights[id]; weekly+=clamp(weeklyConsistency(id,date).percent)*weights[id]; const days=[...Array(28)].filter((_,i)=>dayComplete(id,day(-i,date))).length; stability+=(days/28*100)*weights[id]; }); return Math.round(daily*.35+weekly*.35+stability*.30); }
function buildStreakSummary(date=todayKey()){ const ids=enabledStreakIds(), infos=Object.fromEntries(ids.map(id=>[id,streakInfo(id,date)])); return {score:consistencyScore(date),activities:infos}; }
function recalc(){ Object.values(state.history).forEach(r=>{ r.activityPoints={}; r.totalPoints=0; }); state.log.forEach(e=>{ const d=effectiveDate(e); const r=state.history[d] ||= {date:d,entries:[],activityPoints:{},totalPoints:0}; const p=pointsForEntry(e); r.activityPoints[e.activity]=(r.activityPoints[e.activity]||0)+p; }); Object.entries(state.history).forEach(([date,r])=>{ r.steps=valueFor('dailyStepTarget',date); r.boxBreathingCount=entries(date,'breathing').filter(e=>e.mode==='box').reduce((s,e)=>s+num(e.value),0); r.breathing478Count=entries(date,'breathing').filter(e=>e.mode==='478').reduce((s,e)=>s+num(e.value),0); r.totalPoints=Object.values(r.activityPoints||{}).reduce((a,b)=>a+num(b),0); r.oneUpScore=oneUpScore(date); }); state.points=Object.values(state.history).reduce((s,r)=>s+num(r.totalPoints),0); persist(); }
function oneUpScore(date=todayKey()){ const enabled=Object.keys(activities).filter(id=>state.activitySettings[id]?.enabled); if(!enabled.length) return 0; return Math.round(enabled.reduce((s,id)=>s+activityPercent(id,date),0)/enabled.length); }
function streak(){ const ids=enabledStreakIds(); return ids.length?Math.max(...ids.map(id=>streakInfo(id).current)):0; }
function bestStreak(){ const ids=enabledStreakIds(); return ids.length?Math.max(...ids.map(id=>streakInfo(id).best)):0; }
function addEntry(activity, data){ const e={id:`${Date.now()}-${Math.random().toString(16).slice(2)}`,date:todayKey(),activity,...data}; if(activity==='steps'||activity==='mostSteps'||activity==='dailyStepTarget') state.log=state.log.filter(x=>!(x.date===e.date&&['steps','mostSteps','dailyStepTarget'].includes(x.activity))); state.log.push(e); recalc(); render(); }
function deleteEntry(id){ state.log=state.log.filter(e=>e.id!==id); recalc(); render(); }
function editEntry(id){ const e=state.log.find(x=>x.id===id); if(!e) return; const v=prompt('Ny værdi', e.value ?? e.hours ?? 0); if(v===null) return; if(e.activity==='sleepDuration') e.hours=num(v); else e.value=num(v); recalc(); render(); }
function compareLastWeek(id){ const now=periodValue(id), last=periodValue(id,day(-7)); if(!last && !now) return 'Ingen sammenligning endnu'; const pct= last ? Math.round((now-last)/last*100) : 100; return pct>=0?`+${pct}% mod sidste uge`:`${pct}% mod sidste uge`; }
function renderVersion(){ const label=$('#app-version-label'), build=$('#app-build-label'); if(label) label.textContent=`OneUp Prototype · v${APP_VERSION}`; if(build) build.textContent=APP_BUILD_LABEL; document.querySelectorAll('link[rel="stylesheet"][href^="styles.css"]').forEach(el=>el.href=`styles.css?v=${APP_VERSION}`); document.querySelectorAll('script[src^="script.js"]').forEach(el=>el.src=`script.js?v=${APP_VERSION}`); }
function renderToday(){ const score=oneUpScore(), ids=enabledStreakIds(), infos=ids.map(id=>streakInfo(id)), weeklyDone=ids.reduce((sum,id)=>sum+weeklyConsistency(id).done,0), enabled=activeActivityIds(); $('#oneup-score').textContent=score; $('#today-points').textContent=fmt(state.history[todayKey()].totalPoints); $('#header-points').textContent=fmt(state.points); $('#goals-met').textContent=`${enabled.filter(id=>activityPercent(id)>=100).length}/${enabled.length}`; $('#today-streak').textContent=`${streak()} dage`; $('#encouragement').textContent= score>=90?'Du har allerede slået stærkt igennem i dag.':score>=60?'Du er godt i gang – hold rytmen roligt.':'Start med én lille handling. Det tæller.'; const cs=$('#consistency-section'); if(cs) cs.innerHTML=`<div><p class="eyebrow">Konsistens slår perfektion.</p><h3>Konsistensscore: ${consistencyScore()}/100</h3><p>Én god dag mere bygger videre på rytmen.</p></div><div class="mini-metrics"><span>Længste aktive streak: <b>${bestStreak()}</b></span><span>Aktive streaks: <b>${infos.filter(i=>i.current>0).length}/${ids.length}</b></span><span>Ugens gennemførte dage: <b>${weeklyDone}</b></span></div>`; const summary=$('#today-goal-summary'); if(summary) summary.textContent=enabled.length?`${enabled.filter(id=>activityPercent(id)>=100).length} af ${enabled.length} aktive mål er nået i dag. Detaljer ligger under Aktiviteter og Udvikling.`:'Ingen aktive mål endnu. Vælg aktiviteter for at begynde.'; }
function checkboxRow(attrs, label, extraClass=''){ return `<label class="checkbox-row${extraClass?` ${extraClass}`:''}"><input ${attrs} type="checkbox"><span>${label}</span></label>`; }
function renderActivities(){ $('#activity-manager').innerHTML=Object.entries(activities).map(([id,a])=>{const s=state.activitySettings[id]; return `<article class="card"><div class="card-head"><h3>${a.icon} ${a.name}</h3>${checkboxRow(`data-toggle="${id}" ${s.enabled?'checked':''}`, 'Aktiv')}</div><p>I dag: ${fmt(valueFor(id))} ${a.unit}</p><label class="field">Personligt mål<input data-goal="${id}" type="number" value="${goalFor(id)}" /></label><div class="streak-settings">${checkboxRow(`data-streak-enabled="${id}" ${s.streakEnabled?'checked':''}`, 'Streak til')}<label class="field">Dagligt streak-krav<input data-daily-req="${id}" type="number" value="${dailyRequirementFor(id)}"></label><label class="field">Ugentligt konsistensmål (dage)<input data-weekly-goal="${id}" type="number" min="1" max="7" value="${s.weeklyGoal}"></label>${checkboxRow(`data-protection-enabled="${id}" ${s.protectionEnabled?'checked':''}`, 'Streak-beskyttelse')}${checkboxRow(`data-auto-protection="${id}" ${s.autoProtection?'checked':''}`, 'Brug automatisk streak-beskyttelse')}${id==='sleep'?sleepSettingsHtml(s):''}</div>${a.auto?'<p class="muted">Automatisk registrering kommer senere.</p>':''}<div class="entry-controls">${entryControls(id)}</div></article>`}).join(''); renderEntryList(); }
function sleepSettingsHtml(s){ const c=s.sleepCriteria||{}; return `<div class="sleep-grid"><p><b>Søvnkriterier</b></p>${[['duration','Minimum søvnlængde'],['interval','Ønsket interval'],['bedtime','Sengetid i vindue'],['wake','Opvågning i vindue'],['screenfree','Skærmfri tid før søvn']].map(([k,l])=>checkboxRow(`data-sleep-criterion="${k}" ${c[k]?'checked':''}`, l)).join('')}<label class="field">Minimum timer<input data-sleep-field="sleepMinHours" type="number" step="0.25" value="${s.sleepMinHours}"></label><label class="field">Interval min/max<input data-sleep-field="sleepMinInterval" type="number" step="0.25" value="${s.sleepMinInterval}"><input data-sleep-field="sleepMaxInterval" type="number" step="0.25" value="${s.sleepMaxInterval}"></label><label class="field">Sengetid ± minutter<input data-sleep-field="bedtimeTarget" type="time" value="${s.bedtimeTarget}"><input data-sleep-field="bedtimeTolerance" type="number" value="${s.bedtimeTolerance}"></label><label class="field">Opvågning ± minutter<input data-sleep-field="wakeTarget" type="time" value="${s.wakeTarget}"><input data-sleep-field="wakeTolerance" type="number" value="${s.wakeTolerance}"></label></div>`; }
function entryControls(id){ if(id==='sleep') return '<input data-sleep-start type="time" value="22:30"><input data-sleep-end type="time" value="06:30"><button data-add="sleep">Registrér søvn</button>'; if(id==='meditation') return '<button data-add="meditation" data-value="5">5</button><button data-add="meditation" data-value="10">10</button><button data-add="meditation" data-value="20">20</button><input data-input="meditation" type="number" placeholder="Min"><button data-add="meditation">Gem</button>'; if(id==='running'||id==='cycling') return `<input data-input="${id}" type="number" placeholder="Kilometer"><button data-add="${id}">Gem</button>`; return `<input data-input="${id}" type="number" placeholder="${activityMeta(id).unit}"><button data-add="${id}">Gem</button>`; }
function renderEntryList(){ $('#entry-list').innerHTML=entries().map(e=>`<li>${activityMeta(e.activity).name}: ${fmt(e.value??e.hours)} ${activityMeta(e.activity).unit||''} <button data-edit-entry="${e.id}">Ret</button> <button data-delete-entry="${e.id}">Slet</button></li>`).join('')||'<li>Ingen registreringer i dag endnu.</li>'; }
function renderCompetition(){ const type=$('#competition-type'); if(!type.options.length) ['Procent af eget mål','Længste aktuelle streak','Højeste Konsistensscore','Flest gennemførte dage denne uge','Højeste procent af personligt ugemål','Samlede point'].forEach(x=>type.add(new Option(x,x))); const ids=enabledStreakIds(), weekDone=ids.reduce((s,id)=>s+weeklyConsistency(id).done,0), metric=type.value||'Procent af eget mål'; const you=metric.includes('streak')?streak():metric.includes('Konsistens')?consistencyScore():metric.includes('uge')?weekDone:oneUpScore(); const rows=[['Dig',you,'+8',true],['Amina',Math.max(0,you-3),'+4',true],['Jonas',Math.max(0,you-10),'-2',false],['Sofie',Math.max(0,you-15),'+11',true]]; $('#leaderboard').innerHTML=rows.sort((a,b)=>b[1]-a[1]).map((r,i)=>`<li><b>${i+1}. ${r[0]}</b><span>${r[1]} · ${r[3]?'↗':'↘'} ${r[2]}</span></li>`).join(''); $('#self-summary').innerHTML=[`Nuværende streak mod tidligere rekord: ${streak()} / ${bestStreak()}`,`Denne uges konsistens mod sidste uge: ${weeklyTrend(0)}% / ${weeklyTrend(1)}%`,`Denne måned mod forrige måned: ${monthConsistency(0)}% / ${monthConsistency(1)}%`,`Bedste 28-dages periode: ${best28()}%`,`En enkelt pause sletter ikke din fremgang.`].map(t=>`<article class="card">${t}</article>`).join(''); $('#self-ranking').innerHTML=ids.map((id,i)=>`<li><b>${i+1}. ${activityMeta(id).name}</b><span>${weeklyConsistency(id).percent}% af eget ugemål</span></li>`).join(''); }
function weeklyTrend(w){ const ids=enabledStreakIds(); if(!ids.length) return 0; return Math.round(ids.reduce((s,id)=>s+[0,1,2,3,4,5,6].filter(d=>dayComplete(id,day(-(w*7+d)))).length/7*100,0)/ids.length); }
function monthConsistency(m){ const ids=enabledStreakIds(); if(!ids.length) return 0; return Math.round(ids.reduce((s,id)=>s+[...Array(28)].filter((_,i)=>dayComplete(id,day(-(m*28+i)))).length/28*100,0)/ids.length); }
function best28(){ let best=0; for(let o=0;o<120;o++) best=Math.max(best,monthConsistency(Math.floor(o/28))); return best; }
function weeklyScores(){ return [0,1,2,3,4,5,6,7].map(w=>[0,1,2,3,4,5,6].reduce((s,d)=>s+num(state.history[day(-(w*7+d))]?.totalPoints),0)).sort((a,b)=>b-a); }
function renderDevelopment(){ const filter=$('#development-filter'); if(filter.options.length===1) Object.entries(activities).forEach(([id,a])=>filter.add(new Option(a.name,id))); $('#bars-7').innerHTML=[-6,-5,-4,-3,-2,-1,0].map(o=>{const d=day(o), val=filter.value==='all'?oneUpScore(d):activityPercent(filter.value,d); return `<div><span style="height:${val}%"></span><small>${d.slice(5)}</small></div>`}).join(''); $('#bars-4').innerHTML=[3,2,1,0].map(w=>`<div><span style="height:${weeklyTrend(w)}%"></span><small>Uge ${4-w}</small></div>`).join(''); const ids=enabledStreakIds(), infos=ids.map(id=>streakInfo(id)), best=infos.slice().sort((a,b)=>monthConsistencyFor(b.id)-monthConsistencyFor(a.id))[0], need=infos.slice().sort((a,b)=>monthConsistencyFor(a.id)-monthConsistencyFor(b.id))[0]; const sec=$('#streak-development'); if(sec) sec.innerHTML=`<h3>Streaks og konsistens</h3><div class="card-list">${infos.map(i=>`<article class="card"><h4>${activityMeta(i.id).icon} ${activityMeta(i.id).name}</h4><p>Nuværende: ${i.current} dage · Længste: ${i.best} dage · Senest aktiv: ${i.lastActiveDate||'ingen endnu'}</p><p>Uge: ${i.weekly.done}/${i.weekly.goal} dage (${i.weekly.percent}%) · ${i.weekly.onTrack?'Du er på kurs til ugens mål.':'Begynd igen i dag.'}</p><div class="week-dots">${i.weekly.dates.map(d=>`<span class="${dayComplete(i.id,d)?'done':''}">${d.slice(8)}</span>`).join('')}</div></article>`).join('')}</div><p class="info-box">Seneste 4 ugers konsistens vises ovenfor. Bedste stabilitet: ${best?activityMeta(best.id).name:'ingen endnu'}. Mest brug for kontinuitet: ${need?activityMeta(need.id).name:'ingen endnu'}.</p>`; $('#weekly-summary').innerHTML=['Konsistens slår perfektion.','Én god dag mere bygger videre på rytmen.','En enkelt pause sletter ikke din fremgang.'].map(t=>`<article class="card">${t}</article>`).join(''); }
function monthConsistencyFor(id){ return Math.round([...Array(28)].filter((_,i)=>dayComplete(id,day(-i))).length/28*100); }
function renderProfile(){ const fields=[['nickname','Navn eller kaldenavn','text'],['birthYear','Fødselsår','number'],['height','Højde','number'],['weight','Vægt','number'],['sex','Biologisk køn','text'],['country','Bopælsland','text'],['language','Sprog','text'],['units','Enheder','text']]; $('#profile-form').innerHTML=fields.map(([k,l,t])=>`<label class="field">${l}<input name="${k}" type="${t}" value="${state.profile[k]||''}"></label>`).join('')+'<button>Gem profil</button>'; $('#settings-form').innerHTML=['vibration','sounds','voice'].map(k=>checkboxRow(`data-setting="${k}" ${state.settings[k]?'checked':''}`, k)).join('')+'<label class="field">Uge starter<select data-setting="weekStarts"><option value="monday">Mandag</option><option value="sunday">Søndag</option></select></label>'; }
function render(){ recalcSilently(); recalcCompetitions(); renderVersion(); renderToday(); renderActivities(); renderCompetition(); renderCompetitionSystem(); renderDevelopment(); renderProfile(); bindDynamic(); }
function recalcSilently(){ Object.values(state.history).forEach(r=>{r.activityPoints={};r.totalPoints=0}); state.log.forEach(e=>{const d=effectiveDate(e); const r=state.history[d] ||= {date:d,activityPoints:{}}; const p=pointsForEntry(e); r.activityPoints[e.activity]=(r.activityPoints[e.activity]||0)+p;}); Object.entries(state.history).forEach(([d,r])=>{r.totalPoints=Object.values(r.activityPoints||{}).reduce((s,v)=>s+num(v),0); r.oneUpScore=oneUpScore(d);}); state.points=Object.values(state.history).reduce((s,r)=>s+num(r.totalPoints),0); }
function bindDynamic(){ $$('[data-nav]').forEach(b=>b.onclick=()=>showPage(b.dataset.nav)); $$('[data-toggle]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.toggle].enabled=el.checked; persist(); render();}); $$('[data-goal]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.goal].goal=num(el.value); persist(); render();}); $$('[data-daily-req]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.dailyReq].dailyRequirement=num(el.value); persist(); render();}); $$('[data-weekly-goal]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.weeklyGoal].weeklyGoal=clamp(num(el.value),1,7); persist(); render();}); $$('[data-streak-enabled]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.streakEnabled].streakEnabled=el.checked; persist(); render();}); $$('[data-protection-enabled]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.protectionEnabled].protectionEnabled=el.checked; persist(); render();}); $$('[data-auto-protection]').forEach(el=>el.onchange=()=>{state.activitySettings[el.dataset.autoProtection].autoProtection=el.checked; persist(); render();}); $$('[data-sleep-criterion]').forEach(el=>el.onchange=()=>{state.activitySettings.sleep.sleepCriteria[el.dataset.sleepCriterion]=el.checked; persist(); render();}); $$('[data-sleep-field]').forEach(el=>el.onchange=()=>{state.activitySettings.sleep[el.dataset.sleepField]=el.type==='number'?num(el.value):el.value; persist(); render();}); $$('[data-add]').forEach(b=>b.onclick=()=>manualAdd(b.dataset.add,b)); $$('[data-quick]').forEach(b=>b.onclick=()=>showPage('activities')); $$('[data-delete-entry]').forEach(b=>b.onclick=()=>deleteEntry(b.dataset.deleteEntry)); $$('[data-edit-entry]').forEach(b=>b.onclick=()=>editEntry(b.dataset.editEntry)); }
function manualAdd(id,b){ if(id==='sleepDuration'){ const start=$('[data-sleep-start]').value, end=$('[data-sleep-end]').value, [sh,sm]=start.split(':').map(Number), [eh,em]=end.split(':').map(Number); let h=(eh+em/60)-(sh+sm/60); if(h<0) h+=24; addEntry(id,{value:h,hours:h,start,end,sleepDate:todayKey()}); return; } const input=$(`[data-input="${id}"]`); addEntry(id,{value:num(b.dataset.value ?? input?.value), distance:num($(`[data-distance="${id}"]`)?.value), mode:id==='breathing'?document.querySelector('input[name="breathing-mode"]:checked')?.value:undefined}); }

function activeActivityIds(){ return Object.keys(activities).filter(id=>state.activitySettings[id]?.enabled); }
function userName(){ return state.profile.nickname || 'Dig'; }
function demoParticipants(){ return [{id:'amina',name:'Amina',demo:true,friend:true},{id:'jonas',name:'Jonas',demo:true,friend:true},{id:'sofie',name:'Sofie',demo:true,friend:false}]; }
function defaultWeights(ids){ if(!ids.length) return {}; const base=Math.floor(10000/ids.length)/100, weights=Object.fromEntries(ids.map(id=>[id,base])); weights[ids[0]]=Math.round((100-base*(ids.length-1))*100)/100; return weights; }
function sanitizeActivityIds(ids){ return [...new Set((ids||[]).map(id=>id==='steps'?'dailyStepTarget':normalizeActivityId(id)).filter(id=>allActivities[id]))]; }
function isDeprecatedActivity(id){ return !!deprecatedActivities[normalizeActivityId(id)]; }
function activityMeta(id){ return allActivities[normalizeActivityId(id)] || {id,name:id,icon:'•',description:''}; }

const periodLabels={daily:'pr. dag',averageDaily:'gennemsnit pr. dag',weekly:'pr. uge',competition:'hele konkurrencen',day:'pr. dag',week:'pr. uge'};
const metricUnits={steps:'skridt',sets:'sæt',minutes:'minutter',kilometers:'km',breathingActivities:'aktiviteter',workouts:'træningspas',hours:'timer'};
function baseGoalConfig(id){
  id=normalizeActivityId(id);
  const s=state?.activitySettings?.[id]||{}, a=activityMeta(id);
  if(isDeprecatedActivity(id)) return {activityId:id,metric:'legacy',period:'daily',target:num(s.goal||1),bonusTarget:null,unit:a.unit||'',comparisonMode:'moreIsBetter',scoringMethod:'moreIsBetter',legacyDefault:true,deprecated:true,migrationNotice:'Denne aktivitet bruges ikke længere i nye konkurrencer.'};
  if(id==='mostSteps') return {activityId:id,metric:'steps',unit:'skridt',period:'averageDaily',target:0,bonusTarget:null,comparisonMode:'ranking',scoringMethod:'ranking',legacyDefault:true,complete:true};
  if(id==='dailyStepTarget') return {activityId:id,metric:'steps',unit:'skridt',period:'daily',target:num(s.goal||8000),bonusTarget:null,comparisonMode:'completedDays',scoringMethod:'completedDays',legacyDefault:true};
  if(id==='bedtime') return {activityId:id,metric:'time',unit:'kl.',target:num(s.goal||22.25),bonusTarget:null,comparisonMode:'earlierThanTarget',scoringMethod:'earlierThanTarget',period:'daily',legacyDefault:true};
  if(id==='breathing') return {activityId:id,metric:'breathingActivities',unit:'aktiviteter',target:Math.max(1,Math.ceil(num(s.goal||10)/10)),bonusTarget:null,comparisonMode:'moreIsBetter',scoringMethod:'moreIsBetter',period:'daily',roundsPerActivity:10,migrationNotice:num(s.goal||0)>4?'Dette mål er blevet tilpasset til 10 runder pr. aktivitet. Kontrollér målet.':''};
  if(id==='running'||id==='cycling') return {activityId:id,metric:'kilometers',unit:'km',period:'weekly',target:num(s.goal||a.goal||1),bonusTarget:null,comparisonMode:'moreIsBetter',scoringMethod:'moreIsBetter',legacyDefault:true};
  if(id==='socialMediaFree') return {activityId:id,metric:'minutes',unit:'minutter',period:'daily',target:num(s.goal||60),bonusTarget:null,comparisonMode:'lessIsBetter',scoringMethod:'lessIsBetter',legacyDefault:true};
  return {activityId:id,metric:a.unit==='skridt'?'steps':'minutes',period:a.period==='week'?'weekly':'daily',target:num(s.goal||a.goal||1),bonusTarget:null,unit:a.unit||metricUnits.minutes,comparisonMode:'moreIsBetter',scoringMethod:'moreIsBetter',legacyDefault:true};
}
function normalizeGoalConfig(id,cfg={}){
  id=normalizeActivityId(id); const b=baseGoalConfig(id); const out={...b,...cfg,activityId:id};
  if(id==='breathing' && (out.metric==='rounds'||out.unit==='runder'||num(out.target)>4 && out.roundsPerActivity!==10)){ out.target=Math.max(1,Math.ceil(num(out.target)/10)); out.metric='breathingActivities'; out.unit='aktiviteter'; out.period='daily'; out.roundsPerActivity=10; out.migrationNotice='Dette mål er blevet tilpasset til 10 runder pr. aktivitet. Kontrollér målet.'; }
  if((id==='running'||id==='cycling') && out.metric && out.metric!=='kilometers'){ out.needsReconfiguration=true; out.migrationNotice='Skal konfigureres igen i kilometer'; out.metric='kilometers'; out.unit='km'; out.complete=false; }
  out.target=num(out.target); out.bonusTarget=out.bonusTarget===''?null:(out.bonusTarget==null?null:num(out.bonusTarget)); out.unit=out.unit||metricUnits[out.metric]||b.unit; out.period=id==='breathing'?'daily':(out.period||'daily'); out.comparisonMode=out.comparisonMode||'moreIsBetter'; if(id==='mostSteps'){ out.target=0; out.complete=true; out.comparisonMode='ranking'; out.scoringMethod='ranking'; return out; }
  if(id==='dailyStepTarget') out.comparisonMode='completedDays';
  if(id==='bedtime') out.comparisonMode='earlierThanTarget';
  if(id==='strength'){ out.metric='sets'; out.unit='sæt'; }
  if(id==='socialMediaFree') out.comparisonMode='lessIsBetter'; out.scoringMethod=out.comparisonMode==='lessIsBetter'?'lessIsBetter':(out.comparisonMode==='withinRange'?'withinRange':(out.comparisonMode==='earlierThanTarget'?'earlierThanTarget':'moreIsBetter'));
  const lowerBetter=id==='bedtime'||id==='socialMediaFree';
  out.bonusTarget=null;
  out.complete=!out.needsReconfiguration && (id==='mostSteps' || !!out.target);
  if(id==='breathing' && (!Number.isInteger(out.target)||out.target<1)) out.complete=false;
  return out;
}
function ensureCompetitionGoals(c){ c.activityGoals ||= {}; c.activities=sanitizeActivityIds(c.activities); c.activities.forEach(id=>{ c.activityGoals[id]=normalizeGoalConfig(id,c.activityGoals[id]); }); return c.activityGoals; }
function goalConfig(c,id){ return normalizeGoalConfig(id,(c.activityGoals||{})[id]); }
function scoreMoreIsBetter(value,target){ value=num(value); target=num(target)||1; return value<=target?clamp(value/target*100,0,100):100; }
function scoreLessIsBetter(value,target){ value=num(value); target=num(target)||1; return value<=target?100:clamp(100-(value-target)/target*100,0,100); }
function scoreEarlierThanTarget(value,target,tolerance=60){ value=num(value); target=num(target)||1; return value<=target?100:clamp(100-((value-target)/Math.max(1,num(tolerance)))*100,0,100); }
function scoreWithinRange(value,minimum,maximum,tolerance=0){ value=num(value); minimum=num(minimum); maximum=num(maximum); tolerance=num(tolerance); if(value>=minimum&&value<=maximum) return 100; const diff=value<minimum?minimum-value:value-maximum; return clamp(100-(diff/Math.max(1,tolerance||maximum||minimum))*100,0,100); }
function scoreConsistency(done,total,target){ const ratio=num(done)/Math.max(1,num(target)||num(total)||1); return scoreMoreIsBetter(ratio*100,100); }
function goalSummary(cfg){ cfg=normalizeGoalConfig(cfg.activityId,cfg); if(cfg.deprecated) return `${activityMeta(cfg.activityId).name}: Denne aktivitet bruges ikke længere i nye konkurrencer.`; if(cfg.needsReconfiguration) return cfg.migrationNotice||'Skal konfigureres igen.'; if(cfg.activityId==='mostSteps') return `Flest skridt · Måling: ${cfg.period==='competition'?'Flest skridt i hele konkurrenceperioden':cfg.period==='daily'?'Flest skridt pr. dag':'Højeste gennemsnit pr. dag'}`; if(cfg.activityId==='dailyStepTarget') return `Dagligt skridtmål · Mål: ${fmt(cfg.target)} skridt · Scoring: Antal dage med nået mål`; if(cfg.activityId==='bedtime') return `Sengetid · Mål: senest kl. ${timeLabel(cfg.target)} · Scoring: gennemført dag`; if(cfg.activityId==='breathing') return `Åndedrætsøvelser · Mål: ${fmt(cfg.target)} ${cfg.target===1?'aktivitet':'aktiviteter'} pr. dag · Svarende til ${fmt(cfg.target*10)} runder pr. dag`; if(cfg.activityId==='strength') return `Styrketræning · Mål: ${fmt(cfg.target)} sæt ${periodLabels[cfg.period]||cfg.period}`; if(cfg.activityId==='running'||cfg.activityId==='cycling') return `${activityMeta(cfg.activityId).name} · Mål: ${fmt(cfg.target)} km ${periodLabels[cfg.period]||cfg.period}`; if(cfg.activityId==='socialMediaFree') return `Tid på sociale medier · Mål: højst ${fmt(cfg.target)} minutter ${periodLabels[cfg.period]||cfg.period} · Jo mindre jo bedre`; if(cfg.activityId==='screenFreeBeforeBed') return `Skærmfri før sengetid · Mål: ${fmt(cfg.target)} minutter`; return `${activityMeta(cfg.activityId).name} · Mål: ${fmt(cfg.target)} ${cfg.unit} ${periodLabels[cfg.period]||cfg.period}`; }
function scoringLabelForGoal(cfg){ cfg=normalizeGoalConfig(cfg.activityId,cfg); return cfg.comparisonMode==='ranking'?'Rangliste normaliseret til 0-100':cfg.comparisonMode==='lessIsBetter'?'Mindre er bedre':cfg.comparisonMode==='completedDays'?'Dage med nået mål':cfg.comparisonMode==='earlierThanTarget'?'Til tiden':'Procent af mål'; }
function goalComplete(cfg){ return normalizeGoalConfig(cfg.activityId,cfg).complete; }
function draftGoal(id){ competitionDraft.activityGoals ||= {}; competitionDraft.activityGoals[id] ||= normalizeGoalConfig(id,{target:0,bonusTarget:null,legacyDefault:false,complete:false}); return competitionDraft.activityGoals[id]; }
function wizardIncompleteActivities(d){ return (d.activities||[]).filter(id=>!goalComplete((d.activityGoals||{})[id]||{activityId:id,target:0})); }

function periodGoalForCompetition(id,c,date=todayKey()){ const cfg=goalConfig(c,id), end=(c.endDate&&c.endDate<date)?c.endDate:date, days=dateRange(c.startDate||end,end).length||1; if(cfg.period==='competition') return cfg.target; if(cfg.period==='weekly') return cfg.target*Math.max(1,days/7); return cfg.target*days; }
function competitionPeriodValue(id,participant,c,date=todayKey()){ const end=(c.endDate&&c.endDate<date)?c.endDate:date; return dateRange(c.startDate||end,end).reduce((s,d)=>s+rawActivityValueForParticipant(id,participant,d),0); }
function activityChips(ids,limit=3){ const safe=sanitizeActivityIds(ids); const shown=safe.slice(0,limit).map(id=>{ const a=activityMeta(id); return `<span class="chip ${isDeprecatedActivity(id)?'deprecated':''}" title="${a.description}">${a.icon} ${a.name}${isDeprecatedActivity(id)?' (udgået)':''}</span>`; }).join(''); return shown+(safe.length>limit?`<span class="chip">+${safe.length-limit} aktiviteter</span>`:''); }
function createCompetition(cfg){ const ids=sanitizeActivityIds(cfg.activities||activeActivityIds()); ids.filter(id=>activities[id]).forEach(id=>{ state.activitySettings[id] ||= {...defaultActivitySettings()[id]}; state.activitySettings[id].enabled=true; }); const participants=cfg.type==='self'?[{id:currentUserId,name:userName()}]:[{id:currentUserId,name:userName()},...(cfg.participants||demoParticipants())]; const activityGoals=Object.fromEntries(ids.map(id=>[id,normalizeGoalConfig(id,(cfg.activityGoals||{})[id]||baseGoalConfig(id))])); const c={id:`comp-${Date.now()}-${Math.random().toString(16).slice(2)}`,name:cfg.name||'Ny konkurrence',type:cfg.type||'self',status:'active',creator:currentUserId,leaders:[currentUserId],participants,activities:ids,activityGoals,weighting:{mode:cfg.weightingMode||'equal',weights:cfg.weightingMode==='custom'?Object.fromEntries(ids.map(id=>[id,(cfg.weights||{})[id] ?? (id==='dailyStepTarget'?(cfg.weights||{}).steps:undefined) ?? defaultWeights(ids)[id]])):defaultWeights(ids)},scoringMethod:cfg.scoringMethod||'configuredGoals',startDate:cfg.startDate||todayKey(),endDate:cfg.endDate||day(6),changeLog:[],results:{},settings:{ruleChangeMode:'fromNow',hvrReady:true},createdAt:new Date().toISOString()}; state.competitions.unshift(c); addCompetitionChange(c,'oprettede konkurrencen','-',c.name); recalcCompetitions(); persist(); return c; }
function isCompetitionLeader(c,uid=currentUserId){ return (c.leaders||[]).includes(uid); }
function addCompetitionChange(c,what,oldValue,newValue){ c.changeLog ||= []; c.changeLog.unshift({id:`chg-${Date.now()}-${Math.random().toString(16).slice(2)}`,at:new Date().toISOString(),leaderId:currentUserId,leaderName:userName(),what,oldValue,newValue,mode:'fromNow'}); }
function dateRange(start,end){ const out=[]; for(let d=start,guard=0; d<=end && guard<370; d=day(1,d),guard++) out.push(d); return out; }
function rawActivityValueForParticipant(id,participant,date){ const mine=valueFor(id,date); if(participant.id===currentUserId) return mine; const seed=participant.id.split('').reduce((s,ch)=>s+ch.charCodeAt(0),0)+(date||'').slice(-2)*7; const g=goalFor(id)||1; return Math.round(g*(.55+((seed%70)/100))); }
function sleepCompetitionScore(participant,date){ const base=rawActivityValueForParticipant('sleep',participant,date), g=goalFor('sleep')||8; const duration=Math.min(base/g*75,75), regularity=participant.id===currentUserId && requirementMet('sleep',date)?25:18; return clamp(duration+regularity,0,120); }
function activityEntryPoints(id,participant,date){ if(participant.id!==currentUserId) return Math.round(rawActivityValueForParticipant(id,participant,date)/Math.max(1,goalFor(id))*100); return entries(date,id).reduce((s,e)=>s+pointsForEntry(e),0); }
function baselineFor(id,participant,date){ return [7,8,9,10,11,12,13].reduce((s,o)=>s+rawActivityValueForParticipant(id,participant,day(-o,date)),0)/7 || 1; }
function competitionActivityScore(c,id,participant,date=todayKey()){ id=id==='steps'?'dailyStepTarget':normalizeActivityId(id); if(!allActivities[id]) return 0; ensureCompetitionGoals(c); const cfg=goalConfig(c,id), raw=competitionPeriodValue(id,participant,c,date), g=periodGoalForCompetition(id,c,date)||1; if(c.scoringMethod==='points') return activityEntryPoints(id,participant,date); if(c.scoringMethod==='baseline') return clamp(raw/baselineFor(id,participant,date)*100,0,100); if(c.scoringMethod==='raw') return raw; if(c.scoringMethod==='completedDays') return raw>=g?100:0; if(cfg.comparisonMode==='ranking') return normalizedRankingScore(c,id,participant,date); if(cfg.comparisonMode==='completedDays') return dailyCompletionScore(c,id,participant,date); if(cfg.comparisonMode==='lessIsBetter') return scoreLessIsBetter(raw,g,null); if(cfg.comparisonMode==='withinRange') return scoreWithinRange(raw,cfg.minimum||cfg.target,cfg.maximum||cfg.target,cfg.tolerance||0); if(id==='bedtime') return raw&&raw<=g?100:0; return scoreMoreIsBetter(raw,g,null); }
function dailyCompletionScore(c,id,participant,date=todayKey()){ const cfg=goalConfig(c,id), dates=dateRange(c.startDate||date,(c.endDate&&c.endDate<date)?c.endDate:date); const done=dates.filter(d=>rawActivityValueForParticipant(id,participant,d)>=num(cfg.target)).length; return clamp(done/Math.max(1,dates.length)*100,0,100); }
function normalizedRankingScore(c,id,participant,date=todayKey()){ const vals=(c.participants||[]).map(p=>competitionPeriodValue(id,p,c,date)); const max=Math.max(...vals,0); if(!max) return 0; return clamp(competitionPeriodValue(id,participant,c,date)/max*100,0,100); }
function weightedScore(c,participant,date=todayKey()){ const ids=sanitizeActivityIds(c.activities), weights=c.weighting?.mode==='custom'?c.weighting.weights:defaultWeights(ids); if(!ids.length) return 0; return Math.round(ids.reduce((s,id)=>s+competitionActivityScore(c,id,participant,date)*(weights[id]||0)/100,0)); }
function participantDays(c,p){ return dateRange(c.startDate, (c.endDate&&c.endDate<todayKey())?c.endDate:todayKey()).filter(d=>sanitizeActivityIds(c.activities).some(id=>rawActivityValueForParticipant(id,p,d)>=goalFor(id))).length; }
function participantStreak(c,p){ let n=0; for(let i=0;i<120;i++){ const d=day(-i); if(d<c.startDate) break; if(sanitizeActivityIds(c.activities).some(id=>rawActivityValueForParticipant(id,p,d)>=goalFor(id))) n++; else break; } return n; }
function competitionLeaderboard(c,sort='score',friendsOnly=false){ const rows=(c.participants||[]).filter(p=>!friendsOnly||p.friend||p.id===currentUserId).map(p=>{ const ids=sanitizeActivityIds(c.activities); const per=Object.fromEntries(ids.map(id=>[id,competitionActivityScore(c,id,p)])); const score=weightedScore(c,p), prev=weightedScore(c,p,day(-1)); return {participant:p,perActivity:per,score,change:score-prev,completedDays:participantDays(c,p),streak:participantStreak(c,p),consistency:participantDays(c,p)*10,baseline:Object.values(per).reduce((a,b)=>a+b,0)/(ids.length||1)}; }); const key=sort==='completedDays'?'completedDays':sort==='consistency'?'consistency':sort==='baseline'?'baseline':sanitizeActivityIds(c.activities).includes(sort)?null:'score'; return rows.sort((a,b)=> key?b[key]-a[key]:(b.perActivity[sort]||0)-(a.perActivity[sort]||0)).map((r,i)=>({...r,rank:i+1})); }
function recalcCompetitions(){ (state.competitions||[]).forEach(c=>{ c.activities=sanitizeActivityIds(c.activities); ensureCompetitionGoals(c); c.weighting ||= {mode:'equal',weights:defaultWeights(c.activities)}; if(c.status==='active' && c.endDate<todayKey()){ c.status='finished'; c.finalResults=competitionLeaderboard(c); } c.results={leaderboard:competitionLeaderboard(c),updatedAt:new Date().toISOString(),userScore:weightedScore(c,{id:currentUserId,name:userName()})}; }); }
function archiveCompetition(id){ const c=state.competitions.find(x=>x.id===id); if(c){ c.status='archived'; addCompetitionChange(c,'arkiverede konkurrencen',c.status,'archived'); persist(); render(); } }
function removeLeader(c,uid){ if((c.leaders||[]).length<=1) { alert('Der skal altid være mindst én leder. Udnævn en anden leder først.'); return false; } c.leaders=c.leaders.filter(id=>id!==uid); addCompetitionChange(c,'fjernede lederstatus',uid,'ikke leder'); persist(); render(); return true; }
function ensureCompetitionWizard(){ if($('#competition-wizard')) return; document.body?.insertAdjacentHTML?.('beforeend','<div id="competition-wizard" class="modal" hidden></div>'); }
function renderCompetitionSystem(){ const today=$('[data-page="today"]'); if(today && !$('#competition-home-section')) today.querySelector?.('.score-hero')?.insertAdjacentHTML?.('afterend','<div class="button-row hero-actions"><button id="start-new-competition" data-open-competition-creator>Start ny konkurrence</button></div><section id="competition-home-section"><h2>Igangværende konkurrencer</h2><div id="active-competition-cards"></div></section>'); const compPage=$('[data-page="competition"]'); if(compPage && !$('#competition-system')) compPage.insertAdjacentHTML?.('beforeend','<section id="competition-system"><div class="button-row"><button id="start-new-competition-page" data-open-competition-creator>Start ny konkurrence</button><button class="secondary" id="show-all-competitions">Se alle konkurrencer</button></div><div id="competition-detail"></div><h3>Tidligere konkurrencer</h3><div id="archived-competitions" class="card-list"></div></section>'); ensureCompetitionWizard(); renderHomeCompetitionCards(); renderCompetitionDetail(); bindCompetitionButtons(); }
function competitionStatusLine(c){ const days=Math.max(0,dateRange(todayKey(),c.endDate).length-1), score=c.results?.userScore||0; if(c.type==='self') return `${Math.max(0,score-92)} % bedre end sidste uge · ${days} dage tilbage`; const rank=(c.results?.leaderboard||[]).find(r=>r.participant.id===currentUserId)?.rank||'-'; return `Nr. ${rank} af ${(c.participants||[]).length} · ${score} point · ${days} dage tilbage`; }
function competitionCard(c,full=false){ const collapsed=state.competitionUi.collapsed[c.id] ?? false, leaders=(c.leaders||[]).map(id=>(c.participants||[]).find(p=>p.id===id)?.name||id).join(', '); const lb=competitionLeaderboard(c).slice(0,4); return `<article class="card competition-card ${collapsed?'collapsed':''}"><div class="card-head"><div><h3>${c.name}</h3><p class="muted">${c.type==='self'?'Mod mig selv':'Mod andre'} · ${competitionStatusLine(c)}</p></div><button class="secondary" data-toggle-comp="${c.id}">${collapsed?'Åbn':'Fold sammen'} ▾</button></div>${collapsed?'':`<div class="chip-row">${activityChips(c.activities)}</div><p><b>Konkurrenceledere:</b> ${leaders} <span class="leader-badge">Leder</span></p><p><b>Periode:</b> ${c.startDate} – ${c.endDate}</p><p><b>Scoring:</b> ${scoreLabel(c.scoringMethod)} · <b>Vægtning:</b> ${weightLabel(c)}</p><ol class="leaderboard compact">${lb.map(r=>`<li class="${r.participant.id===currentUserId?'you':''}"><b>${r.rank}. ${r.participant.name}</b><span>${r.score} · ${r.change>=0?'↗':'↘'} ${Math.abs(r.change)}</span></li>`).join('')}</ol><p><b>Din fremgang:</b> ${selfProgressText(c)}</p><div class="button-row"><button data-open-comp="${c.id}">Åbn hele konkurrencen</button>${isCompetitionLeader(c)?'<button class="secondary" data-leader-tools="'+c.id+'">Lederfunktioner</button>':''}</div>`}</article>`; }
function renderHomeCompetitionCards(){ const el=$('#active-competition-cards'); if(!el) return; const active=(state.competitions||[]).filter(c=>c.status==='active'); el.innerHTML=active.length?active.slice(0,3).map(c=>competitionCard(c)).join('')+(active.length>3?'<button id="see-all-competitions">Se alle konkurrencer</button>':''):`<article class="card"><p>Du deltager ikke i en konkurrence endnu.</p><button id="start-first-competition" data-open-competition-creator>Start din første konkurrence</button></article>`; }
function scoreLabel(m){ return {configuredGoals:'Konfigurerede konkurrencemål',goalPercent:'Procent af personligt mål',points:'Samlede aktivitetspoint',baseline:'Forbedring fra egen baseline',raw:'Rå resultater',completedDays:'Antal gennemførte dage'}[m]||m; }
function weightLabel(c){ return c.weighting?.mode==='custom'?Object.entries(c.weighting.weights||{}).map(([id,w])=>`${activityMeta(id).name}: ${w}%`).join(', '):'Lige vægtning'; }
function selfProgressText(c){ if(c.type!=='self') return `Samlet score ${c.results?.userScore||0}`; const rows=(c.activities||[]).map(id=>({id,score:competitionActivityScore(c,id,{id:currentUserId,name:userName()})})).sort((a,b)=>b.score-a.score); return rows[0]?`Din største fremgang er ${activityMeta(rows[0].id).name}. Konsistens tæller mere end perfektion.`:'Klar til start.'; }
function renderCompetitionDetail(){ const arch=$('#archived-competitions'); if(arch) arch.innerHTML=(state.competitions||[]).filter(c=>c.status==='archived'||c.status==='finished').map(c=>`<article class="card"><h3>${c.name}</h3><p>${c.status==='archived'?'Arkiveret':'Afsluttet'} · ${c.finalResults?.[0]?.participant?.name||'Se detaljer'}</p><button data-open-comp="${c.id}">Se detaljer</button></article>`).join('')||'<p class="muted">Ingen tidligere konkurrencer endnu.</p>'; const el=$('#competition-detail'); if(!el) return; const c=state.competitions.find(x=>x.id===selectedCompetitionId)||state.competitions.find(x=>x.status==='active'); if(!c){ el.innerHTML='<article class="card"><h3>Ingen aktiv konkurrence valgt</h3></article>'; return; } selectedCompetitionId=c.id; const lb=competitionLeaderboard(c,$('#competition-sort')?.value||'score',$('#friends-filter')?.checked); const selfRows=sanitizeActivityIds(c.activities).map(id=>({id,score:competitionActivityScore(c,id,{id:currentUserId,name:userName()}),last:competitionActivityScore(c,id,{id:currentUserId,name:userName()},day(-7))})).sort((a,b)=>b.score-a.score); el.innerHTML=`<article class="card detail-card"><p class="eyebrow">Detaljeside</p><h2>${c.name}</h2><p>${c.status==='finished'?'Tillykke med indsatsen. Sejren er god, men konsistensen er endnu vigtigere.':competitionStatusLine(c)}</p><nav class="tabs"><span>Oversigt</span><span>Stilling</span><span>Aktiviteter</span><span>Deltagere</span><span>Regler</span><span>Ændringslog</span></nav><h3>Oversigt</h3>${competitionCard(c,true)}<h3>Stilling</h3>${c.type==='others'?`${checkboxRow('id="friends-filter"', 'Vis kun mine venner')}<label class="field">Sortér<select id="competition-sort"><option value="score">Samlet score</option>${sanitizeActivityIds(c.activities).map(id=>`<option value="${id}">${activityMeta(id).name}</option>`).join('')}<option value="completedDays">Gennemførte dage</option><option value="consistency">Konsistens</option><option value="baseline">Forbedring fra baseline</option></select></label><p class="info-box">Leaderboardet bruger demo-deltagere, indtil login og onlinegrupper tilføjes.</p><ol class="leaderboard">${lb.map(r=>`<li class="${r.participant.id===currentUserId?'you':''}"><b>${r.rank}. ${r.participant.name}${c.leaders.includes(r.participant.id)?' · Leder':''}</b><span>${r.score} point · ${r.change>=0?'↗':'↘'} ${Math.abs(r.change)} · ${r.completedDays} dage · streak ${r.streak}</span></li>`).join('')}</ol>`:`<ol class="leaderboard">${selfRows.map((r,i)=>`<li><b>${i+1}. ${activityMeta(r.id).name}</b><span>${Math.round(r.score/(r.last||100)*100)} % af sidste uge</span></li>`).join('')}</ol><p class="info-box">Denne uge er din 2. bedste af de seneste 8 uger. Du er tæt på din bedste uge.</p>`}<h3>Aktiviteter og regler</h3><div class="chip-row">${Object.keys(activities).map(id=>`${checkboxRow(`data-comp-activity="${id}" ${sanitizeActivityIds(c.activities).includes(id)?'checked':''} ${!isCompetitionLeader(c)?'disabled':''}`, activityMeta(id).name, 'chip')}`).join('')}</div><p>Regelændringer gælder fra ændringstidspunktet. Bagudrettet genberegning kommer senere.</p><h3>Konkurrenceledere</h3><ul class="plain-list">${c.participants.map(p=>`<li>${p.name} ${c.leaders.includes(p.id)?'<span class="leader-badge">Leder</span>':''} ${isCompetitionLeader(c)?`<button data-make-leader="${p.id}">Udnævn</button> <button class="secondary" data-remove-leader="${p.id}">Fjern lederstatus</button>`:''}</li>`).join('')}</ul><h3>Deltagere</h3><ul class="plain-list">${c.participants.map(p=>`<li>${p.name}${p.demo?' · demo-data':''}</li>`).join('')}</ul>${isCompetitionLeader(c)?`<h3>Handlinger for lederen</h3><div class="button-row"><button data-rename-comp="${c.id}">Ændr navn</button><button data-add-demo="${c.id}">Tilføj demo-deltager</button><button class="secondary" data-finish-comp="${c.id}">Afslut konkurrence</button></div>`:''}<h3>Ændringslog</h3><ul class="plain-list">${(c.changeLog||[]).map(l=>`<li>${l.leaderName} ${l.what} den ${new Date(l.at).toLocaleDateString('da-DK')} kl. ${new Date(l.at).toLocaleTimeString('da-DK',{hour:'2-digit',minute:'2-digit'})}. Gammel værdi: ${l.oldValue}. Ny værdi: ${l.newValue}.</li>`).join('')}</ul><div class="button-row"><button data-repeat-comp="${c.id}">Gentag konkurrence</button><button data-clone-comp="${c.id}">Opret ny med samme opsætning</button><button class="secondary" data-archive-comp="${c.id}">Arkivér</button></div></article>`; }
function timeLabel(v){ const total=Math.round(num(v)*60), h=Math.floor(total/60)%24, m=total%60; return `${String(h).padStart(2,'0')}.${String(m).padStart(2,'0')}`; }
function timeInputValue(v){ if(v==null||v==='') return ''; return `${String(Math.floor(num(v))).padStart(2,'0')}:${String(Math.round((num(v)%1)*60)).padStart(2,'0')}`; }
function goalEditorHtml(id){ const cfg=draftGoal(id); let body=''; const unitFor={dailyStepTarget:'skridt',breathing:'aktiviteter',strength:'sæt',running:'kilometer',cycling:'kilometer',socialMediaFree:'minutter',screenFreeBeforeBed:'minutter'}; const input=(label,type,attrs,help='',unit='')=>`<label class="field activity-field goal-input ${type==='time'?'goal-input-time':''}"><span class="goal-input-label">${label}</span><span class="goal-input-wrap"><input class="activity-input ${type==='time'?'activity-time-input':'activity-number-input goal-input-field'}" type="${type==='number'?'text':type}" ${attrs}>${unit?`<span class="goal-input-unit">${unit}</span>`:''}</span></label>${help?`<p class="muted activity-help goal-input-helper">${help}</p>`:''}`; const select=(label,attrs,options)=>`<label class="field activity-field"><span>${label}</span><select class="activity-select" ${attrs}>${options}</select></label>`;
 if(id==='mostSteps') body=`${select('Måleperiode',`data-goal-field="${id}" data-field="period"`, `<option value="daily" ${cfg.period==='daily'?'selected':''}>Flest skridt pr. dag</option><option value="averageDaily" ${cfg.period==='averageDaily'?'selected':''}>Højeste gennemsnit pr. dag</option><option value="competition" ${cfg.period==='competition'?'selected':''}>Flest skridt i hele konkurrenceperioden</option>`)}<p class="info-box">Ingen mål vælges. Deltagere rangeres efter skridt og normaliseres til 0-100, så aktiviteten kan vægtes med målaktiviteter.</p>`;
 else if(id==='dailyStepTarget') body=`${input('Dagligt skridtmål','number',`inputmode="numeric" pattern="[0-9]*" autocomplete="off" data-integer-input="true" data-goal-field="${id}" data-field="target" value="${cfg.target||''}"`,'Eksempel: 8.000 skridt pr. dag. Over målet giver ikke ekstra bonus.','skridt')}<p class="info-box">Flest skridt er rå konkurrence om antal skridt. Dagligt skridtmål handler kun om dage, hvor du når dit eget mål.</p>`;
 else if(id==='bedtime') body=`${input('Seneste sengetidspunkt','time',`data-time-field="${id}" data-field="target" value="${timeInputValue(cfg.target)}"`,'I seng til tiden tæller som gennemført dag. For sent giver ikke bonus eller delscore.')}<p><b>Valgt tidspunkt:</b> ${cfg.target?`kl. ${timeLabel(cfg.target)}`:'Vælg tidspunkt'}</p>`;
 else if(id==='breathing') body=`<p class="info-box">Én aktivitet svarer til 10 fuldførte åndedrætsrunder.</p>${input('Åndedrætsaktiviteter pr. dag','number',`inputmode="numeric" pattern="[0-9]*" autocomplete="off" data-integer-input="true" data-goal-field="${id}" data-field="target" value="${cfg.target||''}"`,'1 aktivitet = 10 fuldførte åndedrætsrunder','aktiviteter')}<p><b>Svarende til:</b> ${fmt((cfg.target||0)*10)} runder pr. dag</p>${cfg.target<1?'<p class="error">Skriv et helt positivt tal.</p>':''}`;
 else if(id==='strength') body=`${select('Periode',`data-goal-field="${id}" data-field="period"`, `<option value="daily" ${cfg.period==='daily'?'selected':''}>sæt pr. dag</option><option value="weekly" ${cfg.period==='weekly'?'selected':''}>sæt pr. uge</option><option value="competition" ${cfg.period==='competition'?'selected':''}>samlede sæt i konkurrencen</option>`)}${input('Antal sæt','number',`inputmode="numeric" pattern="[0-9]*" autocomplete="off" data-integer-input="true" data-goal-field="${id}" data-field="target" value="${cfg.target||''}"`,'Scores som procent af sætmålet, maksimum 100 point.','sæt')}`;
 else if(id==='running'||id==='cycling') body=kmFields(id,cfg);
 else if(id==='socialMediaFree') body=`<p class="info-box">Jo mindre jo bedre.</p>${input('Maksimal tid på sociale medier','number',`inputmode="numeric" pattern="[0-9]*" autocomplete="off" data-integer-input="true" data-goal-field="${id}" data-field="target" value="${cfg.target||''}"`,'Angiv antal minutter.','minutter')}${select('Periode',`data-goal-field="${id}" data-field="period"`, `<option value="daily" ${cfg.period==='daily'?'selected':''}>pr. dag</option><option value="averageDaily" ${cfg.period==='averageDaily'?'selected':''}>gennemsnit pr. dag</option><option value="competition" ${cfg.period==='competition'?'selected':''}>samlet i konkurrencen</option>`)}`;
 else if(id==='screenFreeBeforeBed') body=`${input('Skærmfri før sengetid','number',`inputmode="numeric" pattern="[0-9]*" autocomplete="off" data-integer-input="true" data-goal-field="${id}" data-field="target" value="${cfg.target||''}"`,'Antal minutter før sengetid.','minutter')}`;
 else body=`${input('Mål','number',`inputmode="numeric" pattern="[0-9]*" autocomplete="off" data-integer-input="true" data-goal-field="${id}" data-field="target" value="${cfg.target||''}"`,'',unitFor[id]||'')}${select('Periode',`data-goal-field="${id}" data-field="period"`, `<option value="daily" ${cfg.period==='daily'?'selected':''}>pr. dag</option><option value="weekly" ${cfg.period==='weekly'?'selected':''}>pr. uge</option><option value="competition" ${cfg.period==='competition'?'selected':''}>hele konkurrencen</option>`)}`;
 const notice=cfg.migrationNotice?`<p class="info-box">${cfg.migrationNotice}</p>`:''; return `<div class="activity-config"><h4>Vælg mål for denne konkurrence</h4>${body}<p class="muted">Konkurrencemål er adskilt fra dine personlige hverdagsmål.</p>${notice}<p><b>Opsætning:</b> ${cfg.complete?goalSummary(cfg):'Ufuldstændig'}</p></div>`; }
function kmFields(id,cfg){ return `<label class="field activity-field"><span>Periode</span><select class="activity-select" data-goal-field="${id}" data-field="period"><option value="daily" ${cfg.period==='daily'?'selected':''}>kilometer pr. dag</option><option value="weekly" ${cfg.period==='weekly'?'selected':''}>kilometer pr. uge</option><option value="competition" ${cfg.period==='competition'?'selected':''}>samlede kilometer i konkurrencen</option></select></label><label class="field activity-field goal-input"><span class="goal-input-label">Antal kilometer</span><span class="goal-input-wrap"><input class="activity-input activity-number-input goal-input-field" type="text" inputmode="decimal" autocomplete="off" data-decimal-input="true" data-goal-field="${id}" data-field="target" value="${cfg.target||''}"><span class="goal-input-unit">kilometer</span></span></label><p class="muted activity-help goal-input-helper">Scores som procent af kilometermålet, maksimum 100 point.</p>`; }
function renderWizard(step=1){ ensureCompetitionWizard(); const ids=competitionActivityIds(); competitionDraft ||= {type:'self',name:'Mere bevægelse',activities:[],activityGoals:{},startDate:todayKey(),endDate:day(6),scoringMethod:'configuredGoals',weightingMode:'equal',weights:{},participants:demoParticipants().slice(0,2)}; const w=$('#competition-wizard'); if(!w) return; const d=competitionDraft, sum=Object.values(d.weights||{}).reduce((a,b)=>a+num(b),0), incomplete=wizardIncompleteActivities(d); const activityList=`<p id="activity-validation" class="${!d.activities.length||incomplete.length?'error':'muted'}">${!d.activities.length?'Vælg mindst én aktivitet.':incomplete.length?'Vælg mål for alle aktiviteter.':'Alle valgte aktiviteter er konfigureret.'}</p><div class="competition-activity-list">${ids.map(id=>{ const a=activities[id], selected=d.activities.includes(id), cfg=(d.activityGoals||{})[id]; return `<article class="competition-activity-option ${selected?'selected':''}"><input data-draft-activity="${id}" type="checkbox" ${selected?'checked':''}><span class="activity-icon">${a.icon}</span><span class="activity-content"><strong>${a.name}</strong><span>${a.description}</span>${selected?`<small>${cfg?.complete?goalSummary(cfg):'Ufuldstændig – vælg mål for denne konkurrence'}</small>`:''}</span>${selected?goalEditorHtml(id):''}</article>`; }).join('')}</div>`; const summary=(d.activities||[]).map(id=>`<li>${activityMeta(id).icon} ${activityMeta(id).name}: ${goalSummary(d.activityGoals[id])} · Scoring: ${scoringLabelForGoal(d.activityGoals[id])}</li>`).join(''); const stepHtml={1:`<h3>Trin 1: Vælg konkurrencetype</h3><div class="segmented"><button data-draft="type" data-value="self" class="${d.type==='self'?'active':''}">Mod mig selv</button><button data-draft="type" data-value="others" class="${d.type==='others'?'active':''}">Mod andre</button></div>`,2:`<h3>Trin 2: Navngiv konkurrencen</h3><label class="field">Navn<input id="draft-name" value="${d.name}"></label>`,3:`<h3>Trin 3: Vælg aktiviteter</h3>${activityList}`,4:`<h3>Trin 4: Vælg periode</h3><label class="field">Startdato<input id="draft-start" type="date" value="${d.startDate}"></label><label class="field">Slutdato<input id="draft-end" type="date" value="${d.endDate}"></label><div class="button-row">${[[7,'7 dage'],[14,'14 dage'],[30,'30 dage'],[56,'8 uger']].map(([n,l])=>`<button class="secondary" data-duration="${n}">${l}</button>`).join('')}</div>`,5:`<h3>Trin 5: Scoring</h3><p class="info-box">Konkurrencen bruger de mål, du har valgt pr. aktivitet. Flest skridt normaliseres stabilt til 0-100 efter bedste rå resultat. Målaktiviteter scores som målopfyldelse uden bonusmål.</p>`,6:`<h3>Trin 6: Vægtning</h3><div class="segmented"><button data-weight-mode="equal" class="${d.weightingMode==='equal'?'active':''}">Lige vægtning</button><button data-weight-mode="custom" class="${d.weightingMode==='custom'?'active':''}">Tilpasset vægtning</button></div>${d.activities.map(id=>`<label class="field">${activityMeta(id).icon} ${activityMeta(id).name}<input data-weight="${id}" type="number" step="0.01" value="${d.weights[id]||0}" ${d.weightingMode==='equal'?'readonly':''}></label>`).join('')}<p class="${sum===100?'muted':'error'}">Samlet vægtning: ${sum} %</p>`,7:`<h3>Trin 7: Deltagere</h3>${d.type==='self'?'<p>Du er den eneste deltager.</p>':`<div id="draft-participants">${d.participants.map((p,i)=>`<p>${p.name} · demo-data <button data-remove-demo="${i}">Fjern</button></p>`).join('')}</div><label class="field">Demo-navn<input id="demo-name" placeholder="Navn"></label><button id="add-demo-participant">Tilføj demo-deltager</button>`}`,8:`<h3>Trin 8: Gennemse og opret</h3><ul class="plain-list"><li>Navn: ${d.name}</li><li>Type: ${d.type==='self'?'Mod mig selv':'Mod andre'}</li>${summary}<li>Datoer: ${d.startDate} – ${d.endDate}</li></ul><button id="create-competition-final" ${incomplete.length?'disabled':''}>Opret konkurrence</button>`}[step]; w.hidden=false; w.setAttribute?.('role','dialog'); w.setAttribute?.('aria-modal','true'); w.innerHTML=`<div class="modal-card"><div class="card-head"><h2>Start ny konkurrence</h2><button class="secondary" id="close-wizard">Luk</button></div><p class="muted">Trin ${step} af 8</p>${stepHtml}<div class="button-row"><button class="secondary" id="wizard-prev" ${step===1?'disabled':''}>Tilbage</button><button id="wizard-next" ${step===8?'hidden':''} ${((step===3&&(!d.activities.length||incomplete.length))||(step===6&&sum!==100))?'disabled':''}>Næste</button></div></div>`; bindWizard(step); }
